SELECT metric_id
FROM training_metrics
WHERE explained_variance > 0.7 AND loss_before < 0.2;

SELECT users.user_name, iterations.iteration_id, iterations.iteration_description
FROM iterations
JOIN users ON iterations.user_id = users.user_id;

SELECT users.user_name, models.model_name
FROM users
INNER JOIN models ON users.user_id = models.created_by;

SELECT u.user_name, ur.role_name
FROM users u
INNER JOIN user_roles ur ON u.role = ur.role_name;

SELECT iteration_id, AVG(training_time) AS average_training_time
FROM training_metrics
GROUP BY iteration_id;

SELECT model_id, model_name 
FROM models 
WHERE model_accuracy = (SELECT MAX(model_accuracy) FROM models);

SELECT u.user_name, u.email
FROM users u
JOIN user_roles ur ON u.role = ur.role_name
WHERE ur.permission_level = (
  SELECT MAX(permission_level) FROM user_roles
);

SELECT AVG(loss_before) AS average_loss_before
FROM training_metrics
WHERE explained_variance > 0.8;

SELECT COUNT(*) 
FROM iterations 
WHERE status = 'running';

SELECT user_id, COUNT(access_id) AS access_count
FROM user_access
GROUP BY user_id;

SELECT COUNT(DISTINCT user_id) 
FROM user_access 
WHERE model_id = 3;

SELECT DISTINCT user_name
FROM users
INNER JOIN user_access ON users.user_id = user_access.user_id;
